## Comprehensive shadcn/ui Codebase Structure Report: Adding a Stepper Component

I've thoroughly explored the shadcn/ui codebase. Here's everything you need to know to add a new Stepper component:

---

### 1. DIRECTORY STRUCTURE

**Main Registry Location:**
- `/apps/v4/registry/new-york-v4/` - The primary UI component registry
  - `ui/` - Core UI components (57 files)
  - `examples/` - Component usage examples (237 files)
  - `hooks/` - Custom React hooks
  - `internal/` - Helper components used by complex components
  - `lib/` - Utilities like `utils.ts` with `cn()` function
  - `registry.ts` - Main registry manifest that imports and combines all sub-registries
  - `blocks/` - Full-page template components with multiple sub-components

**Registry Registration System:**
- Each folder has a `_registry.ts` file that exports a `Registry["items"]` array
- The main `registry.ts` combines all registries: `ui`, `examples`, `hooks`, `blocks`, `charts`, `lib`, `internal`, `themes`

**File Paths for Stepper (following conventions):**
```
apps/v4/registry/new-york-v4/
├── ui/stepper.tsx                          # Main component
├── examples/
│   ├── stepper-demo.tsx
│   ├── stepper-vertical.tsx
│   ├── stepper-with-form.tsx
│   └── (additional variants)
└── hooks/use-stepper.ts                    # (if state management needed)
```

---

### 2. COMPOUND COMPONENT PATTERNS (Key Examples)

**A. Simple Compound Pattern - Accordion:**
```tsx
// Location: /apps/v4/registry/new-york-v4/ui/accordion.tsx
// Pattern: Radix-UI primitive wrapper with styled sub-components

"use client"
import * as React from "react"
import { Accordion as AccordionPrimitive } from "radix-ui"
import { cn } from "@/lib/utils"

function Accordion({ ...props }: React.ComponentProps<typeof AccordionPrimitive.Root>) {
  return <AccordionPrimitive.Root data-slot="accordion" {...props} />
}

function AccordionItem({ className, ...props }: React.ComponentProps<typeof AccordionPrimitive.Item>) {
  return (
    <AccordionPrimitive.Item
      data-slot="accordion-item"
      className={cn("border-b last:border-b-0", className)}
      {...props}
    />
  )
}

// Exports all sub-components
export { Accordion, AccordionItem, AccordionTrigger, AccordionContent }
```

**B. Context-Based Pattern with Orientation - Tabs:**
```tsx
// Location: /apps/v4/registry/new-york-v4/ui/tabs.tsx
// Pattern: Supports orientation (horizontal/vertical), uses CVA for variants

function Tabs({
  className,
  orientation = "horizontal",
  ...props
}: React.ComponentProps<typeof TabsPrimitive.Root>) {
  return (
    <TabsPrimitive.Root
      data-slot="tabs"
      data-orientation={orientation}
      orientation={orientation}
      className={cn(
        "group/tabs flex gap-2 data-[orientation=horizontal]:flex-col",
        className
      )}
      {...props}
    />
  )
}

const tabsListVariants = cva(
  "group/tabs-list inline-flex w-fit items-center rounded-lg p-[3px]",
  {
    variants: {
      variant: {
        default: "bg-muted",
        line: "gap-1 bg-transparent",
      },
    },
    defaultVariants: { variant: "default" },
  }
)
```

**C. Context + Child Variants Pattern - ToggleGroup:**
```tsx
// Location: /apps/v4/registry/new-york-v4/ui/toggle-group.tsx
// Pattern: Uses React Context to pass configuration to child components

const ToggleGroupContext = React.createContext<
  VariantProps<typeof toggleVariants> & { spacing?: number }
>({
  size: "default",
  variant: "default",
  spacing: 0,
})

function ToggleGroup({
  className,
  variant,
  size,
  spacing = 0,
  children,
  ...props
}: React.ComponentProps<typeof ToggleGroupPrimitive.Root> &
  VariantProps<typeof toggleVariants> & {
    spacing?: number
  }) {
  return (
    <ToggleGroupPrimitive.Root
      data-slot="toggle-group"
      data-variant={variant}
      data-size={size}
      data-spacing={spacing}
      style={{ "--gap": spacing } as React.CSSProperties}
      className={cn("group/toggle-group flex w-fit items-center gap-[--spacing(var(--gap))]", className)}
      {...props}
    >
      <ToggleGroupContext.Provider value={{ variant, size, spacing }}>
        {children}
      </ToggleGroupContext.Provider>
    </ToggleGroupPrimitive.Root>
  )
}

function ToggleGroupItem({
  className,
  children,
  variant,
  size,
  ...props
}: React.ComponentProps<typeof ToggleGroupPrimitive.Item> &
  VariantProps<typeof toggleVariants>) {
  const context = React.useContext(ToggleGroupContext)

  return (
    <ToggleGroupPrimitive.Item
      data-slot="toggle-group-item"
      data-variant={context.variant || variant}
      data-size={context.size || size}
      className={cn(
        toggleVariants({
          variant: context.variant || variant,
          size: context.size || size,
        }),
        className
      )}
      {...props}
    >
      {children}
    </ToggleGroupPrimitive.Item>
  )
}
```

**D. Complex State Management Pattern - Sidebar:**
```tsx
// Location: /apps/v4/registry/new-york-v4/ui/sidebar.tsx
// Pattern: Full Context + custom hook, state management, keyboard shortcuts, cookies

type SidebarContextProps = {
  state: "expanded" | "collapsed"
  open: boolean
  setOpen: (open: boolean) => void
  openMobile: boolean
  setOpenMobile: (open: boolean) => void
  isMobile: boolean
  toggleSidebar: () => void
}

const SidebarContext = React.createContext<SidebarContextProps | null>(null)

function useSidebar() {
  const context = React.useContext(SidebarContext)
  if (!context) {
    throw new Error("useSidebar must be used within a SidebarProvider.")
  }
  return context
}

function SidebarProvider({
  defaultOpen = true,
  open: openProp,
  onOpenChange: setOpenProp,
  className,
  style,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  defaultOpen?: boolean
  open?: boolean
  onOpenChange?: (open: boolean) => void
}) {
  const isMobile = useIsMobile()
  const [openMobile, setOpenMobile] = React.useState(false)
  const [_open, _setOpen] = React.useState(defaultOpen)
  const open = openProp ?? _open
  const setOpen = React.useCallback(
    (value: boolean | ((value: boolean) => boolean)) => {
      const openState = typeof value === "function" ? value(open) : value
      if (setOpenProp) {
        setOpenProp(openState)
      } else {
        _setOpen(openState)
      }
      // Persists state in cookie
      document.cookie = `sidebar_state=${openState}; path=/; max-age=${60 * 60 * 24 * 7}`
    },
    [setOpenProp, open]
  )

  const state = open ? "expanded" : "collapsed"
  const contextValue = React.useMemo<SidebarContextProps>(
    () => ({ state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar }),
    [state, open, setOpen, isMobile, openMobile, setOpenMobile, toggleSidebar]
  )

  return (
    <SidebarContext.Provider value={contextValue}>
      <div {...props}>
        {children}
      </div>
    </SidebarContext.Provider>
  )
}
```

---

### 3. REGISTRY SYSTEM

**Registry Item Schema (from `/packages/shadcn/src/registry/schema.ts`):**

Each registry item is a discriminated union with these common fields:
```ts
export const registryItemCommonSchema = z.object({
  $schema: z.string().optional(),
  extends: z.string().optional(),
  name: z.string(),                           // Unique identifier
  title: z.string().optional(),               // Display name
  author: z.string().min(2).optional(),
  description: z.string().optional(),
  dependencies: z.array(z.string()).optional(), // npm packages (e.g., "radix-ui")
  devDependencies: z.array(z.string()).optional(),
  registryDependencies: z.array(z.string()).optional(), // Other components (e.g., "button")
  files: z.array(registryItemFileSchema).optional(),
  tailwind: registryItemTailwindSchema.optional(), // Tailwind config
  cssVars: registryItemCssVarsSchema.optional(),   // CSS variables by theme
  css: registryItemCssSchema.optional(),           // Raw CSS
  envVars: registryItemEnvVarsSchema.optional(),
  meta: z.record(z.string(), z.any()).optional(),
  docs: z.string().optional(),
  categories: z.array(z.string()).optional(),
})

// Item types:
registryItemTypeSchema = z.enum([
  "registry:lib",      // Utilities
  "registry:block",    // Full-page templates
  "registry:component", // Reusable components
  "registry:ui",       // UI primitives
  "registry:hook",     // Custom React hooks
  "registry:page",     // Page files
  "registry:file",     // Any file
  "registry:theme",    // Theme configuration
  "registry:style",    // Global styles
  "registry:item",     // Generic
  "registry:base",     // Base setup
  "registry:font",     // Font files
  "registry:example",  // Example/demo files (internal)
  "registry:internal", // Internal helpers (internal)
])
```

**UI Registry Entry Example:**
```ts
