### 5. GENERAL PATTERNS & CONVENTIONS

**A. File Header & Imports:**
```tsx
"use client"  // Required for client-side components

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"  // For variants
import { ComponentPrimitive } from "radix-ui"  // Radix primitives
import { cn } from "@/lib/utils"  // For merging classNames
```

**B. Data-Slot Naming Convention:**
Each component uses `data-slot` for semantic styling and testing:
```tsx
<div data-slot="component-name">
<div data-slot="component-name-item">
<div data-slot="component-name-trigger">
```

**C. Class Merging Utility:**
```tsx
// Location: /apps/v4/registry/new-york-v4/lib/utils.ts

import { clsx, type ClassValue } from "clsx"
import { twMerge } from "tailwind-merge"

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
```

**D. Class Variance Authority (CVA) Pattern:**
```tsx
const stepperItemVariants = cva(
  "flex items-center justify-center rounded-full transition-all",
  {
    variants: {
      status: {
        pending: "bg-muted text-muted-foreground",
        active: "bg-primary text-primary-foreground",
        completed: "bg-green-600 text-white",
      },
      size: {
        sm: "h-8 w-8 text-xs",
