        lg: "h-12 w-12 text-base",
      },
    },
    defaultVariants: {
      status: "pending",
      size: "default",
    },
  }
)
```

**E. Component Props Pattern:**
```tsx
function Component({
  className,
  variant = "default",
  size = "default",
  asChild = false,
  ...props
}: React.ComponentProps<"div"> &
  VariantProps<typeof componentVariants> & {
    asChild?: boolean
  }) {
  const Comp = asChild ? Slot.Root : "div"

  return (
    <Comp
      data-slot="component"
      data-variant={variant}
      data-size={size}
      className={cn(componentVariants({ variant, size, className }))}
      {...props}
    />
  )
}
```

